parameters.jsCode:
const body = $('Webhook Trigger').first().json.body || {};
const promptTemplates = $('Fetch Prompt Templates').first().json.content;
const personalityCalibration = $('Fetch Personality Calibration').first().json.content;

return [{
  json: {
    workflow1_data: {
      task_classification: body.task_classification,
      selected_framework: body.selected_framework,
      alternative_frameworks: body.alternative_frameworks || [],
      personality_tier: body.personality_tier,
      personality_adjustments_preview: body.personality_adjustments_preview || [],
    },
    user_input: {
      task_description: body.original_task_description,
      personality_type: body.personality_type || null,
      trait_percentages: body.trait_percentages || null,
    },
    question_answers: body.question_answers,
    reference_docs: {
      prompt_templates: promptTemplates,
      personality_calibration: personalityCalibration,
    },
  },
}];

parameters.jsonBody:
={{ JSON.stringify({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 8192,
  temperature: 0.3,
  system: `You are an expert prompt engineering assistant. Your task is to construct an optimised prompt using the selected framework, incorporating the user's answers to clarifying questions, and applying appropriate personality-based adjustments.

You have access to two reference documents:

## PROMPT TEMPLATES
${$json.reference_docs.prompt_templates}

## PERSONALITY CALIBRATION
${$json.reference_docs.personality_calibration}

---

## YOUR TASK

1. **Construct the optimised prompt** using the selected framework's template structure
2. **Incorporate all user information** from their task description and question answers
3. **Apply personality adjustments** to language, structure, and format (if personality data exists)
4. **Generate model recommendations** based on task type and requirements
5. **Provide iteration suggestions** for refining the prompt if needed

## IMPORTANT RULES

- The optimised prompt should be COMPLETE and ready for copy/paste into an AI model
- If personality_tier is "none", use neutral language and skip personality adjustments
- Include ALL relevant information from the user's answers
- Make the prompt specific, not generic
- Ensure constraints are clearly stated
- The prompt should be self-contained (the AI receiving it shouldn't need additional context)

## OUTPUT FORMAT

You MUST respond with valid JSON in exactly this structure:

{
  "optimised_prompt": "The complete prompt text, ready for copy/paste. Use \n for line breaks within the prompt.",
  "metadata": {
    "framework_used": {
      "name": "Framework Name",
      "code": "FRAMEWORK_CODE",
      "components": ["Component1", "Component2"],
      "explanation": "Why this framework was selected and how it was applied"
    },
    "personality_adjustments": [
      {
        "trait": "Trait description (e.g., High Thinking 84%)",
        "adjustment": "What was adjusted based on this trait"
      }
    ],
    "model_recommendations": [
      {
        "rank": 1,
        "model": "Model Display Name",
        "model_id": "model-api-identifier",
        "rationale": "Why this model is recommended"
      },
      {
        "rank": 2,
        "model": "Second Choice",
        "model_id": "model-api-identifier",
        "rationale": "Why this is the second choice"
      },
      {
        "rank": 3,
        "model": "Budget Option",
        "model_id": "model-api-identifier",
        "rationale": "Cost-effective alternative"
      }
    ],
    "iteration_suggestions": [
      "Suggestion for refining if output isn't quite right",
      "Another suggestion for a different angle"
    ]
  }
}

Do not include any text outside the JSON structure. Do not use markdown code blocks.`,
  messages: [
    {
      role: 'user',
      content: `Generate an optimised prompt using the following information:

## TASK CLASSIFICATION (from Workflow 1)
${JSON.stringify($json.workflow1_data.task_classification, null, 2)}

## SELECTED FRAMEWORK
${JSON.stringify($json.workflow1_data.selected_framework, null, 2)}

## PERSONALITY TIER
${$json.workflow1_data.personality_tier}

## PERSONALITY ADJUSTMENTS TO APPLY
${JSON.stringify($json.workflow1_data.personality_adjustments_preview, null, 2)}

---

## ORIGINAL TASK DESCRIPTION
${$json.user_input.task_description}

## PERSONALITY DATA
${$json.user_input.personality_type ? 'Type: ' + $json.user_input.personality_type + ($json.user_input.trait_percentages ? '
Percentages: ' + JSON.stringify($json.user_input.trait_percentages) : '') : 'None provided - use neutral defaults'}

## USER'S ANSWERS TO CLARIFYING QUESTIONS
${JSON.stringify($json.question_answers, null, 2)}

---

Now construct the optimised prompt incorporating all this information.`
    }
  ]
}) }}

